raw:
{
  "qa_list": [
    {
      "q": "텍스트 기반 추론형 AI 데이터셋이 고난이도화되는 방향은 어떻게 구성됩니까?",
      "a": "텍스트 기반 추론형 AI 데이터셋은 일반 상식과 기초 수학 문제를 넘어 점차 고난이도화되고 있으며, 메타-추론이나 전문가 수준의 문제를 풀 수 있는 방향으로 진화하고 있습니다.",
      "intent": "how",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '일반 상식과 기초 수학 문제를 넘어 점차 고난이도화되고, 메타-추론이나 전문가 수준 문제를 풀 수 있는 방향으로 진화하고 있습니다'에 직접 근거",
        "2) 질문 구성 방식 — 데이터셋의 난이도 진화 방향이라는 단일 차원 내에서, 출발점(일반 상식·기초 수학)과 진화 방향(메타-추론·전문가 수준) 두 항목을 모두 포함하는 how형 질문으로 구성"
      ],
      "answerable": true
    },
    {
      "q": "멀티모달 추론 데이터셋이 추구하는 목적은 무엇입니까?",
      "a": "멀티모달 추론 데이터셋은 AI 모델이 텍스트, 이미지, 비디오 등 여러 양식의 정보를 동시에 이해하고 종합하여 복잡한 결론을 도출하도록 도와 인간과 유사한 인지 능력을 갖도록 하는 데 목적이 있습니다.",
      "intent": "purpose",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '멀티모달 추론 데이터셋은 AI 모델이 텍스트, 이미지, 비디오 등 여러 양식의 정보를 동시에 이해하고 종합하여 복잡한 결론을 도출하도록 도와 인간과 유사한 인지 능력을 갖도록 하는 데 목적이 있습니다'라는 명시적 목적 문구가 존재",
        "2) 질문 구성 방식 — purpose 허용 조건인 '~에 목적이 있습니다'라는 명시적 문구가 컨텍스트에 존재하므로 purpose형으로 구성하였으며, 목적 달성의 수단(여러 양식 정보의 동시 이해·종합)과 최종 목표(인간과 유사한 인지 능력)를 모두 포함"
      ],
      "answerable": true
    },
    {
      "q": "텍스트 기반 추론형 AI 데이터셋과 멀티모달 추론 데이터셋은 데이터 구성 구조와 처리 대상 정보 양식에서 어떻게 구분됩니까?",
      "a": "텍스트 기반 추론형 AI 데이터셋은 질문-추론-답변 구조로 구성되며, 처리 대상이 텍스트 기반의 논리적 사고 및 문제 해결에 집중됩니다. 반면 멀티모달 추론 데이터셋은 텍스트, 이미지, 비디오 등 여러 양식의 정보를 동시에 이해하고 종합하는 것을 처리 대상으로 합니다.",
      "intent": "comparison",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 텍스트 기반 데이터셋의 구조는 '질문-추론-답변 구조로 구성'에 근거하고, 멀티모달 데이터셋의 처리 대상은 '텍스트, 이미지, 비디오 등 여러 양식의 정보를 동시에 이해하고 종합'에 근거하며, 두 대상 모두 컨텍스트에 명시됨",
        "2) 질문 구성 방식 — 두 데이터셋 유형을 비교하는 comparison형으로 구성하였으며, 데이터 구성 구조(텍스트 기반: 질문-추론-답변)와 처리 대상 정보 양식(텍스트 단독 vs. 텍스트·이미지·비디오 복합)이라는 두 속성이 각각 컨텍스트에 명시되어 있음"
      ],
      "answerable": true
    }
  ]
}

{
  "qa_list": [
    {
      "q": "멀티모달 추론 데이터셋이 AI 모델 훈련에 필수적인 이유는 무엇입니까?",
      "a": "멀티모달 추론 데이터셋은 AI 모델이 단순한 패턴 인식을 넘어 실세계의 복잡한 정보를 통합하고 인간과 유사한 인지 능력을 갖도록 훈련하는 데 필수적입니다. 또한 AI의 추론 능력과 설명 가능성을 향상시키는 역할을 합니다.",
      "intent": "purpose",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '이러한 데이터셋은 단순한 패턴 인식을 넘어, AI가 실세계의 복잡한 정보를 통합하고 인간과 유사한 인지 능력을 갖도록 훈련하는 데 필수적이며 AI의 추론 능력과 설명 가능성을 향상시킨다'는 명시적 목적 문구가 존재함",
        "2) 질문 구성 방식 — 컨텍스트에 '~하는 데 필수적이며', '~을 향상시킨다'는 목적·기능 문구가 명시되어 있으므로 purpose 유형으로 구성 가능"
      ],
      "answerable": true
    },
    {
      "q": "멀티모달 추론 데이터셋의 대표적인 유형과 각 유형의 특성은 무엇입니까?",
      "a": "멀티모달 추론 데이터셋의 대표적인 유형으로는 VideoCoT, VideoEspresso, MathVista가 있습니다. VideoCoT는 비디오 단계적 추론을 다루며, VideoEspresso는 상황적 인과 파악을 목적으로 하고, MathVista는 시각과 수학 논리를 결합한 특성을 지닙니다.",
      "intent": "list",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 'VideoCoT(비디오 단계적 추론), VideoEspresso(상황적 인과 파악), MathVista(시각-수학 논리 결합) 등이 있다'고 명시적으로 열거되어 있음",
        "2) 질문 구성 방식 — 복수의 구체적 데이터셋 유형과 각각의 특성이 괄호 안에 함께 서술되어 있으므로, 유형과 특성을 함께 묻는 list 질문으로 구성"
      ],
      "answerable": true
    },
    {
      "q": "멀티모달 추론 데이터셋이 처리하는 정보의 양식 범위와 이를 통해 AI 모델이 수행하는 작업은 어떻게 구분됩니까?",
      "a": "멀티모달 추론 데이터셋이 처리하는 정보의 양식은 텍스트, 이미지, 비디오 등 여러 양식입니다. 이를 통해 AI 모델은 해당 양식의 정보를 동시에 이해하고 종합하여 복잡한 결론을 도출하는 작업을 수행합니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 'AI 모델이 텍스트, 이미지, 비디오 등 여러 양식의 정보를 동시에 이해하고 종합하여 복잡한 결론을 도출하도록 돕는 특수 데이터이다'라고 명시되어 있음",
        "2) 질문 구성 방식 — 처리 대상 양식(텍스트·이미지·비디오)과 AI 모델이 수행하는 작업(동시 이해·종합·결론 도출)이라는 두 가지 사실 요소를 단일 fact 차원 내에서 구분하여 묻는 형태로 구성"
      ],
      "answerable": true
    }
  ]
}

{
  "qa_list": [
    {
      "q": "추론형 AI 데이터 생성 방식 중 LLM 자동 생성 방식과 인적 어노테이션 방식은 품질 및 확장성 측면에서 어떻게 구분됩니까?",
      "a": "인적 어노테이션 방식은 논리적·사실적 측면에서 품질이 매우 높으나 확장성이 제한적입니다. 반면 LLM 자동 생성 방식은 품질이 불균일하고 모델 출력 편차가 발생할 수 있으나 확장성이 매우 높습니다. 즉, 두 방식은 품질과 확장성 측면에서 상반된 특성을 보입니다.",
      "intent": "comparison",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 인적 어노테이션: '품질이 매우 높고(논리적, 사실적)', '확장성이 제한적'; LLM 자동 생성: '품질이 불균일하고 모델 출력 편차가 발생', '확장성이 매우 높음' — 양쪽 모두 품질·확장성 속성이 존재하여 P7 대칭 검증 통과",
        "2) 질문 구성 방식 — comparison 단일 차원 안에서 두 대상(인적 어노테이션 vs LLM 자동 생성)의 동일 속성(품질, 확장성)을 비교하며, 차원 혼합 없음"
      ],
      "answerable": true
    },
    {
      "q": "하이브리드 방식이 인적 어노테이션 방식 및 LLM 자동 생성 방식과 비교하여 비용/시간 및 일관성 관리 측면에서 어떠한 특성을 가집니까?",
      "a": "하이브리드 방식의 비용/시간은 중간 수준으로, 비용/시간이 높은 인적 어노테이션 방식과 비용/시간이 매우 낮은 LLM 자동 생성 방식의 중간에 위치합니다. 일관성 관리 측면에서는 인적 어노테이션 방식이 어노테이션별 편차가 발생할 수 있고, LLM 자동 생성 방식이 모델 출력 편차가 발생할 수 있는 반면, 하이브리드 방식은 검수를 통해 일관성을 보완할 수 있습니다.",
      "intent": "comparison",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 하이브리드: '비용/시간은 중간 수준', '일관성 관리는 검수로 보완 가능'; 인적 어노테이션: '비용/시간이 높고', '어노테이션별 편차가 발생'; LLM 자동 생성: '비용/시간이 매우 낮고', '모델 출력 편차가 발생' — 세 방식 모두 비용/시간·일관성 속성이 존재하여 P7 대칭 검증 통과",
        "2) 질문 구성 방식 — comparison 단일 차원 안에서 세 방식의 동일 속성(비용/시간, 일관성 관리)을 비교하며, 차원 혼합 없음"
      ],
      "answerable": true
    },
    {
      "q": "추론형 AI 데이터 생성 방식 중 인적 어노테이션, LLM 자동 생성, 하이브리드 방식의 대표 활용 예시는 각각 무엇입니까?",
      "a": "인적 어노테이션 방식의 대표 활용 예시는 Minerva와 GSM8K(expert labeling)입니다. LLM 자동 생성 방식의 대표 활용 예시는 Self-Instruct와 DeepSeek CoT(auto)입니다. 하이브리드 방식의 대표 활용 예시는 Grok과 VideoEspresso(HITL)입니다.",
      "intent": "list",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 인적 어노테이션: 'Minerva, GSM8K(expert labeling)'; LLM 자동 생성: 'Self-Instruct, DeepSeek CoT(auto)'; 하이브리드: 'Grok, VideoEspresso(HITL)' — 세 방식 모두 대표 활용 예시가 컨텍스트에 명시되어 있음",
        "2) 질문 구성 방식 — list 단일 차원 안에서 세 방식의 대표 활용 예시를 열거하며, P5에 따라 모든 항목을 빠짐없이 포함함"
      ],
      "answerable": true
    }
  ]
}

{
  "qa_list": [
    {
      "q": "멀티모달 데이터 중심 접근에서 VLM이 CoT를 확장하여 수행하는 추론의 유형과 활용하는 데이터 형식은 무엇입니까?",
      "a": "VLM(Visual Language Model)은 CoT를 확장하여 공간 추론 및 시각 추론을 수행합니다. 이때 활용하는 데이터 형식은 이미지-텍스트 쌍이며, VQA 데이터셋이 대표적인 예시로 사용됩니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — 'VLM(Visual Language Model)에서 CoT를 확장해 공간/시각 추론을 수행하며, 데이터는 이미지-텍스트 쌍(예: VQA 데이터셋)을 사용한다'는 컨텍스트 문장에 직접 근거함.",
        "2) 질문 구성 방식 — 추론 유형(공간/시각 추론)과 데이터 형식(이미지-텍스트 쌍)이라는 동일한 'fact' 차원 내 두 요소를 연결하여 학습 가치 있는 질문을 구성함."
      ],
      "answerable": true
    },
    {
      "q": "멀티모달 추론을 위한 주요 접근방식에는 어떠한 것들이 있으며, 각각의 특성은 무엇입니까?",
      "a": "멀티모달 추론의 주요 접근방식은 세 가지입니다. 첫째, Multimodal CoT는 시각과 텍스트를 결합한 체인 방식으로 추론을 수행합니다. 둘째, M-ICL(멀티모달 인컨텍스트 학습)은 멀티모달 환경에서 인컨텍스트 학습을 적용하는 방식입니다. 셋째, Multimodal ToT는 트리 기반의 멀티모달 탐색 방식으로 추론을 수행합니다.",
      "intent": "list",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '주요 접근방식으로는 Multimodal CoT (시각-텍스트 체인), M-ICL (멀티모달 인컨텍스트 학습), Multimodal ToT (트리 기반 멀티모달 탐색) 등이 있다'는 컨텍스트 문장에 세 가지 항목이 명시되어 있음.",
        "2) 질문 구성 방식 — 컨텍스트에 열거된 세 가지 접근방식 모두를 포함하여 완전성을 확보하고, 각각의 특성(시각-텍스트 체인, 인컨텍스트 학습, 트리 기반 탐색)까지 서술하도록 질문을 구성함."
      ],
      "answerable": true
    },
    {
      "q": "멀티모달 CoT와 Multimodal ToT는 추론 구조 측면에서 어떻게 구분됩니까?",
      "a": "Multimodal CoT는 시각과 텍스트를 결합한 체인(chain) 구조로 추론을 수행합니다. 반면 Multimodal ToT는 트리(tree) 기반의 멀티모달 탐색 구조로 추론을 수행합니다. 즉, CoT는 선형적인 체인 방식인 데 비해 ToT는 트리 형태의 탐색 방식이라는 점에서 구조적으로 구분됩니다.",
      "intent": "comparison",
